// symbolGeometry holds the resolved symbol geometry for one legend item.
type symbolGeom struct {
	Size  float64
	Cy    float64
	Shape SymbolShape
}

// symbolGeometry resolves a legend item's symbol geometry using defaults when
// the props fields are zero.
func symbolGeometry(p LegendProps) symbolGeom {
	g := symbolGeom{Size: p.SymbolSize, Cy: p.ItemHeight / 2, Shape: p.SymbolShape}
	if g.Size == 0 {
		g.Size = LegendDefaults.SymbolSize
	}
	if g.Cy == 0 {
		g.Cy = LegendDefaults.ItemHeight / 2
	}
	if g.Shape == "" {
		g.Shape = LegendDefaults.SymbolShape
	}
	return g
}

// symbolLabelX returns the label x offset given the item direction.
func symbolLabelX(p LegendProps) float64 {
	size := p.SymbolSize
	if size == 0 {
		size = LegendDefaults.SymbolSize
	}
	spacing := p.SymbolSpacing
	if spacing == 0 {
		spacing = LegendDefaults.SymbolSpacing
	}
	switch p.ItemDirection {
	case LegendItemDirectionRightToLeft:
		return -spacing
	case LegendItemDirectionTopToBottom, LegendItemDirectionBottomToTop:
		return size / 2
	default: // left-to-right
		return size + spacing
	}
}

// symbolLabelY returns the label y offset given the item direction.
func symbolLabelY(p LegendProps) float64 {
	h := p.ItemHeight
	if h == 0 {
		h = LegendDefaults.ItemHeight
	}
	size := p.SymbolSize
	if size == 0 {
		size = LegendDefaults.SymbolSize
	}
	switch p.ItemDirection {
	case LegendItemDirectionTopToBottom:
		return size + (h-size)/2
	case LegendItemDirectionBottomToTop:
		return h - size - (h-size)/2
	default:
		return h / 2
	}
}

// itemTextAnchor returns the text-anchor for a legend item label.
func itemTextAnchor(p LegendProps) string {
	switch p.ItemDirection {
	case LegendItemDirectionRightToLeft:
		return "end"
	case LegendItemDirectionTopToBottom, LegendItemDirectionBottomToTop:
		return "middle"
	default:
		return "start"
	}
}

func fmtN(v float64) string {
	return fmt.Sprintf("%.3g", v)
}

